import{c as r,Q as e,j as d,m as o}from"./chunks/framework.DpF7k2f3.js";const c=JSON.parse('{"title":"访问 http://localhost:80``` |","description":"","frontmatter":{"outline":"deep"},"headers":[],"relativePath":"zh/appendix/appendix-a.md","filePath":"zh/appendix/appendix-a.md"}'),a={name:"zh/appendix/appendix-a.md"};function n(s,t,h,l,i,g){return e(),d("div",null,[...t[0]||(t[0]=[o('<h5 id="附录a-ai应用开发工具速查表" tabindex="-1">附录A AI应用开发工具速查表 <a class="header-anchor" href="#附录a-ai应用开发工具速查表" aria-label="Permalink to &quot;附录A AI应用开发工具速查表&quot;">​</a></h5><p>本附录整理了AI应用开发全流程中常用的工具，按功能类别分组。每个工具均提供官方链接、核心定位、适用场景及快速上手命令，方便在实际项目中快速查阅。</p><hr><h4 id="a-1-大模型服务" tabindex="-1">A.1 大模型服务 <a class="header-anchor" href="#a-1-大模型服务" aria-label="Permalink to &quot;A.1 大模型服务&quot;">​</a></h4><h6 id="a-1-1-openai" tabindex="-1">A.1.1 OpenAI <a class="header-anchor" href="#a-1-1-openai" aria-label="Permalink to &quot;A.1.1 OpenAI&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://platform.openai.com" target="_blank" rel="noreferrer">https://platform.openai.com</a></td></tr><tr><td><strong>一句话定位</strong></td><td>全球领先的通用大模型服务，GPT-4系列模型行业标杆</td></tr><tr><td><strong>适用场景</strong></td><td>对话生成、代码编写、复杂推理、内容创作</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import openairesponse = openai.ChatCompletion.create( model=&quot;gpt-4&quot;, messages=[{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;Hello!&quot;}])print(response.choices[0].message.content)```</td><td></td></tr></tbody></table><h6 id="a-1-2-通义千问-qwen" tabindex="-1">A.1.2 通义千问（Qwen） <a class="header-anchor" href="#a-1-2-通义千问-qwen" aria-label="Permalink to &quot;A.1.2 通义千问（Qwen）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://tongyi.aliyun.com/qianwen/" target="_blank" rel="noreferrer">https://tongyi.aliyun.com/qianwen/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/QwenLM/Qwen" target="_blank" rel="noreferrer">https://github.com/QwenLM/Qwen</a></td></tr><tr><td><strong>一句话定位</strong></td><td>阿里云开源大模型，中文能力强，支持长上下文</td></tr><tr><td><strong>适用场景</strong></td><td>中文对话、文档分析、Agent开发、私有部署</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from openai import OpenAIclient = OpenAI(api_key=&quot;sk-xxx&quot;, base_url=&quot;<a href="https://dashscope.aliyuncs.com/compatible-mode/v1" target="_blank" rel="noreferrer">https://dashscope.aliyuncs.com/compatible-mode/v1</a>&quot;)response = client.chat.completions.create(model=&quot;qwen-plus&quot;, messages=[{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;你好&quot;}])</td><td></td></tr><tr><td>print(response.choices[0].message.content)```</td><td></td></tr></tbody></table><h6 id="a-1-3-文心一言-ernie-bot" tabindex="-1">A.1.3 文心一言（ERNIE Bot） <a class="header-anchor" href="#a-1-3-文心一言-ernie-bot" aria-label="Permalink to &quot;A.1.3 文心一言（ERNIE Bot）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://yiyan.baidu.com/" target="_blank" rel="noreferrer">https://yiyan.baidu.com/</a></td></tr><tr><td><strong>文档</strong></td><td><a href="https://cloud.baidu.com/doc/wenxinworkshop/s/6lkhf37n9" target="_blank" rel="noreferrer">https://cloud.baidu.com/doc/wenxinworkshop/s/6lkhf37n9</a></td></tr><tr><td><strong>一句话定位</strong></td><td>百度自研大模型，深度融合中文知识与搜索能力</td></tr><tr><td><strong>适用场景</strong></td><td>中文智能问答、内容生成、百度生态集成</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import ernieboterniebot.api_type = &#39;aistudio&#39;erniebot.access_token = &#39;&#39;</td><td></td></tr><tr><td>response = erniebot.ChatCompletion.create(model=&#39;ernie-4.0-8k-latest&#39;, messages=[{&#39;role&#39;: &#39;user&#39;, &#39;content&#39;: &#39;你好&#39;}])```</td><td></td></tr></tbody></table><h6 id="a-1-4-deepseek" tabindex="-1">A.1.4 DeepSeek <a class="header-anchor" href="#a-1-4-deepseek" aria-label="Permalink to &quot;A.1.4 DeepSeek&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.deepseek.com/" target="_blank" rel="noreferrer">https://www.deepseek.com/</a></td></tr><tr><td><strong>API文档</strong></td><td><a href="https://platform.deepseek.com/docs" target="_blank" rel="noreferrer">https://platform.deepseek.com/docs</a></td></tr><tr><td><strong>一句话定位</strong></td><td>国产开源大模型，代码能力出色，推理成本低</td></tr><tr><td><strong>适用场景</strong></td><td>代码生成、数学推理、高性价比私有部署</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from openai import OpenAIclient = OpenAI(api_key=&quot;sk-xxx&quot;, base_url=&quot;<a href="https://api.deepseek.com" target="_blank" rel="noreferrer">https://api.deepseek.com</a>&quot;)response = client.chat.completions.create(model=&quot;deepseek-chat&quot;, messages=[{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;用Python实现快速排序&quot;}])</td><td></td></tr><tr><td>print(response.choices[0].message.content)```</td><td></td></tr></tbody></table><h6 id="a-1-5-智谱ai-glm" tabindex="-1">A.1.5 智谱AI（GLM） <a class="header-anchor" href="#a-1-5-智谱ai-glm" aria-label="Permalink to &quot;A.1.5 智谱AI（GLM）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.zhipuai.cn/" target="_blank" rel="noreferrer">https://www.zhipuai.cn/</a></td></tr><tr><td><strong>API文档</strong></td><td><a href="https://open.bigmodel.cn/dev/api" target="_blank" rel="noreferrer">https://open.bigmodel.cn/dev/api</a></td></tr><tr><td><strong>一句话定位</strong></td><td>清华智谱自研大模型，ChatGLM系列开源影响力大</td></tr><tr><td><strong>适用场景</strong></td><td>对话交互、Agent开发、中英双语任务</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from zhipuai import ZhipuAIclient = ZhipuAI(api_key=&quot;xxx&quot;)response = client.chat.completions.create(model=&quot;glm-4&quot;, messages=[{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;你好&quot;}])</td><td></td></tr><tr><td>print(response.choices[0].message.content)```</td><td></td></tr></tbody></table><h6 id="a-1-6-moonshot-月之暗面kimi" tabindex="-1">A.1.6 Moonshot（月之暗面Kimi） <a class="header-anchor" href="#a-1-6-moonshot-月之暗面kimi" aria-label="Permalink to &quot;A.1.6 Moonshot（月之暗面Kimi）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.moonshot.cn/" target="_blank" rel="noreferrer">https://www.moonshot.cn/</a></td></tr><tr><td><strong>API文档</strong></td><td><a href="https://platform.moonshot.cn/docs" target="_blank" rel="noreferrer">https://platform.moonshot.cn/docs</a></td></tr><tr><td><strong>一句话定位</strong></td><td>支持超长上下文（128K），擅长长文档处理</td></tr><tr><td><strong>适用场景</strong></td><td>长文本分析、合同审核、论文总结</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from openai import OpenAI</td><td></td></tr><tr><td>client = OpenAI(api_key=&quot;sk-xxx&quot;, base_url=&quot;<a href="https://api.moonshot.cn/v1" target="_blank" rel="noreferrer">https://api.moonshot.cn/v1</a>&quot;)response = client.chat.completions.create(model=&quot;moonshot-v1-128k&quot;, messages=[{&quot;role&quot;: &quot;user&quot;, &quot;content&quot;: &quot;分析这份长文档的核心观点&quot;}])</td><td></td></tr><tr><td>print(response.choices[0].message.content)```</td><td></td></tr></tbody></table><h6 id="a-1-7-vllm" tabindex="-1">A.1.7 vLLM <a class="header-anchor" href="#a-1-7-vllm" aria-label="Permalink to &quot;A.1.7 vLLM&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://docs.vllm.ai/" target="_blank" rel="noreferrer">https://docs.vllm.ai/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/vllm-project/vllm" target="_blank" rel="noreferrer">https://github.com/vllm-project/vllm</a></td></tr><tr><td><strong>一句话定位</strong></td><td>高性能LLM推理框架，PagedAttention实现高效显存管理</td></tr><tr><td><strong>适用场景</strong></td><td>生产环境LLM服务、高并发推理、私有模型部署</td></tr><tr><td><strong>快速上手</strong></td><td>```bash# 启动vLLM服务</td></tr><tr><td>python -m vllm.entrypoints.openai.api_server --model Qwen/Qwen2-7B-Instruct --port 8000```</td><td></td></tr></tbody></table><h6 id="a-1-8-ollama" tabindex="-1">A.1.8 Ollama <a class="header-anchor" href="#a-1-8-ollama" aria-label="Permalink to &quot;A.1.8 Ollama&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://ollama.com/" target="_blank" rel="noreferrer">https://ollama.com/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/ollama/ollama" target="_blank" rel="noreferrer">https://github.com/ollama/ollama</a></td></tr><tr><td><strong>一句话定位</strong></td><td>本地大模型运行工具，一键部署开源模型</td></tr><tr><td><strong>适用场景</strong></td><td>本地开发测试、个人学习、离线环境</td></tr><tr><td><strong>快速上手</strong></td><td>```bash# 安装并运行模型</td></tr><tr><td>ollama pull llama3</td><td></td></tr><tr><td>ollama run llama3 &quot;解释什么是RAG&quot;```</td><td></td></tr></tbody></table><hr><h4 id="a-2-框架与编排" tabindex="-1">A.2 框架与编排 <a class="header-anchor" href="#a-2-框架与编排" aria-label="Permalink to &quot;A.2 框架与编排&quot;">​</a></h4><h6 id="a-2-1-langchain" tabindex="-1">A.2.1 LangChain <a class="header-anchor" href="#a-2-1-langchain" aria-label="Permalink to &quot;A.2.1 LangChain&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.langchain.com/" target="_blank" rel="noreferrer">https://www.langchain.com/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/langchain-ai/langchain" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langchain</a></td></tr><tr><td><strong>一句话定位</strong></td><td>大模型应用开发基础框架，提供组件化抽象</td></tr><tr><td><strong>适用场景</strong></td><td>Chain构建、Prompt管理、工具调用、多模态处理</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from langchain_openai import ChatOpenAI</td><td></td></tr><tr><td>from langchain.prompts import PromptTemplate</td><td></td></tr><tr><td>llm = ChatOpenAI(model=&quot;gpt-4&quot;)prompt = PromptTemplate.from_template(&quot;用{language}实现{algorithm}&quot;)chain = prompt</td><td>llm</td></tr><tr><td>print(chain.invoke({&quot;language&quot;: &quot;Python&quot;, &quot;algorithm&quot;: &quot;快速排序&quot;}))```</td><td></td></tr></tbody></table><h6 id="a-2-2-langgraph" tabindex="-1">A.2.2 LangGraph <a class="header-anchor" href="#a-2-2-langgraph" aria-label="Permalink to &quot;A.2.2 LangGraph&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://langchain-ai.github.io/langgraph/" target="_blank" rel="noreferrer">https://langchain-ai.github.io/langgraph/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/langchain-ai/langgraph" target="_blank" rel="noreferrer">https://github.com/langchain-ai/langgraph</a></td></tr><tr><td><strong>一句话定位</strong></td><td>基于LangChain的循环任务编排，支撑复杂Agent流程</td></tr><tr><td><strong>适用场景</strong></td><td>多步骤Agent、循环推理、工作流编排、状态机开发</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from langgraph.graph import StateGraph, START, END</td><td></td></tr><tr><td>from langgraph.graph import MessagesState</td><td></td></tr><tr><td>def should_continue(state): return &quot;end&quot; if len(state[&quot;messages&quot;]) &gt; 5 else &quot;continue&quot;</td><td></td></tr><tr><td>workflow = StateGraph(MessagesState)</td><td></td></tr><tr><td>workflow.add_node(&quot;call_model&quot;, lambda state: {&quot;messages&quot;: [llm.invoke(state[&quot;messages&quot;])]})</td><td></td></tr><tr><td>workflow.add_edge(START, &quot;call_model&quot;)</td><td></td></tr><tr><td>workflow.add_edge(&quot;call_model&quot;, should_continue)</td><td></td></tr><tr><td>app = workflow.compile()```</td><td></td></tr></tbody></table><h6 id="a-2-3-llamaindex" tabindex="-1">A.2.3 LlamaIndex <a class="header-anchor" href="#a-2-3-llamaindex" aria-label="Permalink to &quot;A.2.3 LlamaIndex&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.llamaindex.ai/" target="_blank" rel="noreferrer">https://www.llamaindex.ai/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/run-llama/llama_index" target="_blank" rel="noreferrer">https://github.com/run-llama/llama_index</a></td></tr><tr><td><strong>一句话定位</strong></td><td>专注RAG的数据框架，提供强大的数据索引与检索能力</td></tr><tr><td><strong>适用场景</strong></td><td>RAG开发、私域知识库、文档问答、上下文增强</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from llama_index.core import VectorStoreIndex, SimpleDirectoryReader</td><td></td></tr><tr><td>documents = SimpleDirectoryReader(&quot;./data&quot;).load_data()index = VectorStoreIndex.from_documents(documents)</td><td></td></tr><tr><td>query_engine = index.as_query_engine()</td><td></td></tr><tr><td>print(query_engine.query(&quot;核心内容是什么？&quot;))```</td><td></td></tr></tbody></table><h6 id="a-2-4-crewai" tabindex="-1">A.2.4 CrewAI <a class="header-anchor" href="#a-2-4-crewai" aria-label="Permalink to &quot;A.2.4 CrewAI&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.crewai.io/" target="_blank" rel="noreferrer">https://www.crewai.io/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/joaomdmoura/crewai" target="_blank" rel="noreferrer">https://github.com/joaomdmoura/crewai</a></td></tr><tr><td><strong>一句话定位</strong></td><td>多Agent协作框架，强调角色分工与任务委派</td></tr><tr><td><strong>适用场景</strong></td><td>多Agent团队协作、复杂任务分解与并行执行</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from crewai import Agent, Task, Crew</td><td></td></tr><tr><td>researcher = Agent(role=&quot;研究员&quot;, goal=&quot;调研AI趋势&quot;, backstory=&quot;专业科技分析师&quot;, verbose=True)</td><td></td></tr><tr><td>research_task = Task(description=&quot;分析2024年AI大模型进展&quot;, agent=researcher)</td><td></td></tr><tr><td>crew = Crew(agents=[researcher], tasks=[research_task])</td><td></td></tr><tr><td>result = crew.kickoff()```</td><td></td></tr></tbody></table><h6 id="a-2-5-autogen" tabindex="-1">A.2.5 AutoGen <a class="header-anchor" href="#a-2-5-autogen" aria-label="Permalink to &quot;A.2.5 AutoGen&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://microsoft.github.io/autogen/" target="_blank" rel="noreferrer">https://microsoft.github.io/autogen/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/microsoft/autogen" target="_blank" rel="noreferrer">https://github.com/microsoft/autogen</a></td></tr><tr><td><strong>一句话定位</strong></td><td>微软开源多Agent对话框架，支持人机协作</td></tr><tr><td><strong>适用场景</strong></td><td>多Agent对话、代码生成与执行、人机协同任务</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from autogen import ConversableAgent</td><td></td></tr><tr><td>assistant = ConversableAgent(&quot;assistant&quot;, llm_config={&quot;model&quot;: &quot;gpt-4&quot;})user_proxy = ConversableAgent(&quot;user&quot;, human_input_mode=&quot;NEVER&quot;)</td><td></td></tr><tr><td>chat_result = user_proxy.initiate_chat(assistant, message=&quot;帮我写一个Hello World程序&quot;)```</td><td></td></tr></tbody></table><h6 id="a-2-6-dify" tabindex="-1">A.2.6 Dify <a class="header-anchor" href="#a-2-6-dify" aria-label="Permalink to &quot;A.2.6 Dify&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://dify.ai/" target="_blank" rel="noreferrer">https://dify.ai/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/langgenius/dify" target="_blank" rel="noreferrer">https://github.com/langgenius/dify</a></td></tr><tr><td><strong>一句话定位</strong></td><td>开源LLM应用开发平台，低代码构建AI工作流</td></tr><tr><td><strong>适用场景</strong></td><td>快速原型开发、企业级AI应用、非技术人员友好</td></tr><tr><td><strong>快速上手</strong></td><td>```bash# Docker部署Dify</td></tr><tr><td>git clone <a href="https://github.com/langgenius/dify.git" target="_blank" rel="noreferrer">https://github.com/langgenius/dify.git</a></td><td></td></tr><tr><td>cd dify/docker</td><td></td></tr><tr><td>docker-compose up -d</td><td></td></tr></tbody></table><h1 id="访问-http-localhost-80" tabindex="-1">访问 http://localhost:80``` | <a class="header-anchor" href="#访问-http-localhost-80" aria-label="Permalink to &quot;访问 http://localhost:80``` |&quot;">​</a></h1><h6 id="a-2-7-coze-扣子" tabindex="-1">A.2.7 Coze（扣子） <a class="header-anchor" href="#a-2-7-coze-扣子" aria-label="Permalink to &quot;A.2.7 Coze（扣子）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.coze.cn/" target="_blank" rel="noreferrer">https://www.coze.cn/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>字节跳动一站式AI应用开发平台，集成Bot开发与发布</td></tr><tr><td><strong>适用场景</strong></td><td>快速搭建聊天机器人、工作流编排、插件开发</td></tr><tr><td><strong>快速上手</strong></td><td>```python# Coze API调用示例</td></tr><tr><td>import requests</td><td></td></tr><tr><td>response = requests.post(&quot;<a href="https://api.coze.com/v1/chat" target="_blank" rel="noreferrer">https://api.coze.com/v1/chat</a>&quot;, headers={&quot;Authorization&quot;: &quot;Bearer $API_TOKEN&quot;}, json={&quot;bot_id&quot;: &quot;$BOT_ID&quot;, &quot;user_id&quot;: &quot;user_123&quot;, &quot;query&quot;: &quot;你好&quot;})```</td><td></td></tr></tbody></table><hr><h4 id="a-3-向量数据库" tabindex="-1">A.3 向量数据库 <a class="header-anchor" href="#a-3-向量数据库" aria-label="Permalink to &quot;A.3 向量数据库&quot;">​</a></h4><h6 id="a-3-1-chroma" tabindex="-1">A.3.1 Chroma <a class="header-anchor" href="#a-3-1-chroma" aria-label="Permalink to &quot;A.3.1 Chroma&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.trychroma.com/" target="_blank" rel="noreferrer">https://www.trychroma.com/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/chroma-core/chroma" target="_blank" rel="noreferrer">https://github.com/chroma-core/chroma</a></td></tr><tr><td><strong>一句话定位</strong></td><td>轻量级嵌入式向量数据库，开发友好，适合快速原型</td></tr><tr><td><strong>适用场景</strong></td><td>原型开发、Small Data RAG、Python原生集成</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import chromadb</td><td></td></tr><tr><td>client = chromadb.Client()collection = client.create_collection(&quot;documents&quot;)collection.add(ids=[&quot;1&quot;], embeddings=[[0.1, 0.2]], documents=[&quot;示例文档&quot;])</td><td></td></tr><tr><td>results = collection.query(query_embeddings=[[0.1, 0.2]], n_results=1)```</td><td></td></tr></tbody></table><h6 id="a-3-2-qdrant" tabindex="-1">A.3.2 Qdrant <a class="header-anchor" href="#a-3-2-qdrant" aria-label="Permalink to &quot;A.3.2 Qdrant&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://qdrant.tech/" target="_blank" rel="noreferrer">https://qdrant.tech/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/qdrant/qdrant" target="_blank" rel="noreferrer">https://github.com/qdrant/qdrant</a></td></tr><tr><td><strong>一句话定位</strong></td><td>高性能向量数据库，支持过滤条件与混合搜索</td></tr><tr><td><strong>适用场景</strong></td><td>生产级RAG、密集检索+稀疏检索混合、实时推荐</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from qdrant_client import QdrantClient</td><td></td></tr><tr><td>client = QdrantClient(url=&quot;<a href="http://localhost:6333" target="_blank" rel="noreferrer">http://localhost:6333</a>&quot;)client.upload_collection(collection_name=&quot;docs&quot;, vectors={&quot;1&quot;: [0.1, 0.2]}, payload=[{&quot;text&quot;: &quot;文档内容&quot;}])</td><td></td></tr><tr><td>results = client.search(collection_name=&quot;docs&quot;, query_vector=[0.1, 0.2], limit=5)```</td><td></td></tr></tbody></table><h6 id="a-3-3-milvus" tabindex="-1">A.3.3 Milvus <a class="header-anchor" href="#a-3-3-milvus" aria-label="Permalink to &quot;A.3.3 Milvus&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://milvus.io/" target="_blank" rel="noreferrer">https://milvus.io/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/milvus-io/milvus" target="_blank" rel="noreferrer">https://github.com/milvus-io/milvus</a></td></tr><tr><td><strong>一句话定位</strong></td><td>云原生分布式向量数据库，支撑十亿级向量检索</td></tr><tr><td><strong>适用场景</strong></td><td>超大规模向量检索、企业级应用、多模态搜索</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from pymilvus import connections, Collection</td><td></td></tr><tr><td>connections.connect(host=&quot;localhost&quot;, port=&quot;19530&quot;)</td><td></td></tr><tr><td>collection = Collection(&quot;documents&quot;)collection.load()</td><td></td></tr><tr><td>results = collection.search(data=[[0.1, 0.2]], anns_field=&quot;vector&quot;, limit=10)```</td><td></td></tr></tbody></table><h6 id="a-3-4-pinecone" tabindex="-1">A.3.4 Pinecone <a class="header-anchor" href="#a-3-4-pinecone" aria-label="Permalink to &quot;A.3.4 Pinecone&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.pinecone.io/" target="_blank" rel="noreferrer">https://www.pinecone.io/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>全托管云向量数据库，零运维即用的Serverless服务</td></tr><tr><td><strong>适用场景</strong></td><td>云原生应用、快速上线、无需运维基础设施</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import pinecone</td><td></td></tr><tr><td>pinecone.init(api_key=&quot;xxx&quot;, environment=&quot;us-west1-gcp&quot;)pinecone.create_index(&quot;documents&quot;, dimension=1536)index = pinecone.Index(&quot;documents&quot;)index.upsert([(&quot;1&quot;, [0.1]*1536, {&quot;text&quot;: &quot;文档内容&quot;})])</td><td></td></tr><tr><td>results = index.query(vector=[0.1]*1536, top_k=5)```</td><td></td></tr></tbody></table><h6 id="a-3-5-weaviate" tabindex="-1">A.3.5 Weaviate <a class="header-anchor" href="#a-3-5-weaviate" aria-label="Permalink to &quot;A.3.5 Weaviate&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://weaviate.io/" target="_blank" rel="noreferrer">https://weaviate.io/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/weaviate/weaviate" target="_blank" rel="noreferrer">https://github.com/weaviate/weaviate</a></td></tr><tr><td><strong>一句话定位</strong></td><td>矢量搜索引擎，原生支持混合搜索与知识图谱</td></tr><tr><td><strong>适用场景</strong></td><td>混合搜索（向量+关键词）、知识图谱增强、多模态</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import weaviate</td><td></td></tr><tr><td>client = weaviate.Client(&quot;<a href="http://localhost:8080" target="_blank" rel="noreferrer">http://localhost:8080</a>&quot;)client.data_object.create(class_name=&quot;Document&quot;, properties={&quot;content&quot;: &quot;文档内容&quot;})</td><td></td></tr><tr><td>results = client.query.get(&quot;Document&quot;, [&quot;content&quot;]).with_near_vector({&quot;vector&quot;: [0.1, 0.2]}).do()```</td><td></td></tr></tbody></table><hr><h4 id="a-4-embedding模型" tabindex="-1">A.4 Embedding模型 <a class="header-anchor" href="#a-4-embedding模型" aria-label="Permalink to &quot;A.4 Embedding模型&quot;">​</a></h4><h6 id="a-4-1-openai-embeddings" tabindex="-1">A.4.1 OpenAI Embeddings <a class="header-anchor" href="#a-4-1-openai-embeddings" aria-label="Permalink to &quot;A.4.1 OpenAI Embeddings&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://platform.openai.com/docs/guides/embeddings" target="_blank" rel="noreferrer">https://platform.openai.com/docs/guides/embeddings</a></td></tr><tr><td><strong>一句话定位</strong></td><td>text-embedding-ada-002/text-embedding-3系列，标准化程度高</td></tr><tr><td><strong>适用场景</strong></td><td>通用文本嵌入、跨模态应用、快速集成</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import openai</td><td></td></tr><tr><td>response = openai.Embedding.create(input=&quot;要嵌入的文本&quot;, model=&quot;text-embedding-3-small&quot;)</td><td></td></tr><tr><td>embedding = response.data[0].embedding```</td><td></td></tr></tbody></table><h6 id="a-4-2-bge-baai-general-embedding" tabindex="-1">A.4.2 BGE（BAAI General Embedding） <a class="header-anchor" href="#a-4-2-bge-baai-general-embedding" aria-label="Permalink to &quot;A.4.2 BGE（BAAI General Embedding）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://github.com/FlagOpen/FlagEmbedding" target="_blank" rel="noreferrer">https://github.com/FlagOpen/FlagEmbedding</a></td></tr><tr><td><strong>一句话定位</strong></td><td>智谱BGE系列开源模型，中文能力优秀，支持多语言</td></tr><tr><td><strong>适用场景</strong></td><td>中文RAG、私有部署、国产化适配</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from FlagEmbedding import BGEM3FlagModel</td><td></td></tr><tr><td>model = BGEM3FlagModel(&quot;BAAI/bge-m3&quot;, use_fp16=True)</td><td></td></tr><tr><td>embeddings = model.encode(&quot;要嵌入的文本&quot;)[&quot;dense_vectors&quot;]```</td><td></td></tr></tbody></table><h6 id="a-4-3-gte-general-text-embedding" tabindex="-1">A.4.3 GTE（General Text Embedding） <a class="header-anchor" href="#a-4-3-gte-general-text-embedding" aria-label="Permalink to &quot;A.4.3 GTE（General Text Embedding）&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://modelscope.cn/models/TongyiFinance/gte-collection" target="_blank" rel="noreferrer">https://modelscope.cn/models/TongyiFinance/gte-collection</a></td></tr><tr><td><strong>一句话定位</strong></td><td>阿里通义开源Embedding模型，支持中英双语</td></tr><tr><td><strong>适用场景</strong></td><td>双语文档检索、跨境应用、阿里云集成</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from modelscope import AutoModelForSequenceEmbedding</td><td></td></tr><tr><td>model = AutoModelForSequenceEmbedding.from_pretrained(&quot;gte-large-zh&quot;)</td><td></td></tr><tr><td>result = model.encode([[&quot;中文文本&quot;, &quot;English text&quot;]])```</td><td></td></tr></tbody></table><h6 id="a-4-4-jina-embeddings" tabindex="-1">A.4.4 Jina Embeddings <a class="header-anchor" href="#a-4-4-jina-embeddings" aria-label="Permalink to &quot;A.4.4 Jina Embeddings&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://jina.ai/embeddings/" target="_blank" rel="noreferrer">https://jina.ai/embeddings/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>Jina AI开源Embedding服务，支持长上下文与多语言</td></tr><tr><td><strong>适用场景</strong></td><td>长文档嵌入、开发者友好、多语言应用</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import requests</td><td></td></tr><tr><td>response = requests.post(&quot;<a href="https://api.jina.ai/v1/embeddings" target="_blank" rel="noreferrer">https://api.jina.ai/v1/embeddings</a>&quot;, headers={&quot;Authorization&quot;: &quot;Bearer jina_xxx&quot;}, json={&quot;input&quot;: &quot;文本&quot;, &quot;model&quot;: &quot;jina-embeddings-v3&quot;})```</td><td></td></tr></tbody></table><h6 id="a-4-5-cohere-embeddings" tabindex="-1">A.4.5 Cohere Embeddings <a class="header-anchor" href="#a-4-5-cohere-embeddings" aria-label="Permalink to &quot;A.4.5 Cohere Embeddings&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://cohere.com/embed" target="_blank" rel="noreferrer">https://cohere.com/embed</a></td></tr><tr><td><strong>一句话定位</strong></td><td>Cohere Embed v3支持100+语言，高维嵌入精度优异</td></tr><tr><td><strong>适用场景</strong></td><td>多语言应用、企业级搜索、国际化RAG</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>import cohere</td><td></td></tr><tr><td>co = cohere.Client(&quot;xxx&quot;)</td><td></td></tr><tr><td>response = co.embed(texts=[&quot;文本&quot;], model=&quot;embed-english-v3.0&quot;)</td><td></td></tr><tr><td>embedding = response.embeddings[0]```</td><td></td></tr></tbody></table><hr><h4 id="a-5-重排序模型" tabindex="-1">A.5 重排序模型 <a class="header-anchor" href="#a-5-重排序模型" aria-label="Permalink to &quot;A.5 重排序模型&quot;">​</a></h4><h6 id="a-5-1-cohere-rerank" tabindex="-1">A.5.1 Cohere Rerank <a class="header-anchor" href="#a-5-1-cohere-rerank" aria-label="Permalink to &quot;A.5.1 Cohere Rerank&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://cohere.com/rerank" target="_blank" rel="noreferrer">https://cohere.com/rerank</a></td></tr><tr><td><strong>一句话定位</strong></td><td>基于LLM的排序模型，显著提升检索结果相关性</td></tr><tr><td><strong>适用场景</strong></td><td>检索结果精排、多候选排序、搜索增强</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>response = co.rerank(query=&quot;查询&quot;, documents=[&quot;文档1&quot;, &quot;文档2&quot;], model=&quot;rerank-multilingual-v3.0&quot;, top_n=3)</td><td></td></tr><tr><td>for result in response.results:</td><td></td></tr></tbody></table><pre><code>print(f&quot;文档: {result.document.text}, 分数: {result.relevance_score}&quot;)``` |\n</code></pre><h6 id="a-5-2-bge-reranker" tabindex="-1">A.5.2 BGE-Reranker <a class="header-anchor" href="#a-5-2-bge-reranker" aria-label="Permalink to &quot;A.5.2 BGE-Reranker&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/FlagOpen/FlagEmbedding" target="_blank" rel="noreferrer">https://github.com/FlagOpen/FlagEmbedding</a></td></tr><tr><td><strong>一句话定位</strong></td><td>BAAI开源重排序模型，中文场景效果好</td></tr><tr><td><strong>适用场景</strong></td><td>国产化RAG流水线、中文检索精排</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from FlagEmbedding import FlagReranker</td><td></td></tr><tr><td>reranker = FlagReranker(&quot;BAAI/bge-reranker-v2-m3&quot;, use_fp16=True)</td><td></td></tr><tr><td>scores = reranker.compute_score([[query, doc] for doc in documents])```</td><td></td></tr></tbody></table><h6 id="a-5-3-bce-reranker" tabindex="-1">A.5.3 BCE Reranker <a class="header-anchor" href="#a-5-3-bce-reranker" aria-label="Permalink to &quot;A.5.3 BCE Reranker&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/netease-youdao/bce-reranker" target="_blank" rel="noreferrer">https://github.com/netease-youdao/bce-reranker</a></td></tr><tr><td><strong>一句话定位</strong></td><td>网易有道开源中文重排序模型，高效易用</td></tr><tr><td><strong>适用场景</strong></td><td>中文文档精排、教育/知识库场景</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from bcere Reranker import BCEReranker</td><td></td></tr><tr><td>reranker = BCEReranker(&quot;bce-reranker-base-v1&quot;)</td><td></td></tr><tr><td>scores = reranker rerank(query, documents, top_k=10)```</td><td></td></tr></tbody></table><hr><h4 id="a-6-部署工具" tabindex="-1">A.6 部署工具 <a class="header-anchor" href="#a-6-部署工具" aria-label="Permalink to &quot;A.6 部署工具&quot;">​</a></h4><h6 id="a-6-1-fastapi" tabindex="-1">A.6.1 FastAPI <a class="header-anchor" href="#a-6-1-fastapi" aria-label="Permalink to &quot;A.6.1 FastAPI&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://fastapi.tiangolo.com/" target="_blank" rel="noreferrer">https://fastapi.tiangolo.com/</a></td></tr><tr><td><strong>GitHub</strong></td><td><a href="https://github.com/tiangolo/fastapi" target="_blank" rel="noreferrer">https://github.com/tiangolo/fastapi</a></td></tr><tr><td><strong>一句话定位</strong></td><td>现代Python Web框架，自动生成API文档，性能优秀</td></tr><tr><td><strong>适用场景</strong></td><td>LLM API封装、RAG服务发布、模型推理接口</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from fastapi import FastAPI</td><td></td></tr><tr><td>app = FastAPI()</td><td></td></tr><tr><td>@app.post(&quot;/chat&quot;)</td><td></td></tr><tr><td>async def chat(message: str):</td><td></td></tr></tbody></table><pre><code>return {&quot;response&quot;: f&quot;收到: {message}&quot;}``` |\n</code></pre><h6 id="a-6-2-docker" tabindex="-1">A.6.2 Docker <a class="header-anchor" href="#a-6-2-docker" aria-label="Permalink to &quot;A.6.2 Docker&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://www.docker.com/" target="_blank" rel="noreferrer">https://www.docker.com/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>容器化平台，实现应用与环境的一致性交付</td></tr><tr><td><strong>适用场景</strong></td><td>模型服务打包、环境隔离、一键部署</td></tr><tr><td><strong>快速上手</strong></td><td>```dockerfile# Dockerfile示例</td></tr><tr><td>FROM python:3.11-slim</td><td></td></tr><tr><td>WORKDIR /app</td><td></td></tr><tr><td>COPY requirements.txt .</td><td></td></tr><tr><td>RUN pip install -r requirements.txt</td><td></td></tr><tr><td>COPY . .</td><td></td></tr><tr><td>CMD [&quot;uvicorn&quot;, &quot;main:app&quot;, &quot;--host&quot;, &quot;0.0.0.0&quot;]```</td><td></td></tr></tbody></table><h6 id="a-6-3-docker-compose" tabindex="-1">A.6.3 Docker Compose <a class="header-anchor" href="#a-6-3-docker-compose" aria-label="Permalink to &quot;A.6.3 Docker Compose&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://docs.docker.com/compose/" target="_blank" rel="noreferrer">https://docs.docker.com/compose/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>多容器编排工具，定义和管理多服务应用</td></tr><tr><td><strong>适用场景</strong></td><td>RAG全链路部署（LLM+向量库+API）、本地开发环境</td></tr><tr><td><strong>快速上手</strong></td><td>```yamlversion: &#39;3.8&#39;</td></tr><tr><td>services:</td><td></td></tr><tr><td>api:</td><td></td></tr></tbody></table><pre><code>build: .\nports:\n  - &quot;8000:8000&quot;\n</code></pre><p>qdrant: image: qdrant/qdrant ports: - &quot;6333:6333&quot;``` |</p><h6 id="a-6-4-kubernetes" tabindex="-1">A.6.4 Kubernetes <a class="header-anchor" href="#a-6-4-kubernetes" aria-label="Permalink to &quot;A.6.4 Kubernetes&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://kubernetes.io/" target="_blank" rel="noreferrer">https://kubernetes.io/</a></td></tr><tr><td><strong>一句话定位</strong></td><td>容器编排平台，支撑生产级弹性扩缩容</td></tr><tr><td><strong>适用场景</strong></td><td>企业级AI服务编排、微服务治理、高可用部署</td></tr><tr><td><strong>快速上手</strong></td><td>```yamlapiVersion: apps/v1</td></tr><tr><td>kind: Deployment</td><td></td></tr><tr><td>metadata:</td><td></td></tr><tr><td>name: llm-service</td><td></td></tr><tr><td>spec:</td><td></td></tr><tr><td>replicas: 3</td><td></td></tr><tr><td>selector:</td><td></td></tr></tbody></table><pre><code>matchLabels:\n  app: llm\n</code></pre><p>template: spec: containers: - name: api image: my-llm-api:latest ports: - containerPort: 8000``` |</p><hr><h4 id="a-7-数据与文档处理" tabindex="-1">A.7 数据与文档处理 <a class="header-anchor" href="#a-7-数据与文档处理" aria-label="Permalink to &quot;A.7 数据与文档处理&quot;">​</a></h4><h6 id="a-7-1-llamaparse" tabindex="-1">A.7.1 LlamaParse <a class="header-anchor" href="#a-7-1-llamaparse" aria-label="Permalink to &quot;A.7.1 LlamaParse&quot;">​</a></h6><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>官网</strong></td><td><a href="https://cloud.llamaindex.ai/parse" target="_blank" rel="noreferrer">https://cloud.llamaindex.ai/parse</a></td></tr><tr><td><strong>一句话定位</strong></td><td>专为LLM优化的文档解析服务，支持复杂PDF结构</td></tr><tr><td><strong>适用场景</strong></td><td>复杂文档RAG、表格提取、多页布局解析</td></tr><tr><td><strong>快速上手</strong></td><td>```python</td></tr><tr><td>from llama_parse import LlamaParse</td><td></td></tr><tr><td>parser = LlamaParse(api_key=&quot;llx-xxx&quot;, result_type=&quot;markdown&quot;) <strong>使用提示</strong>：</td><td></td></tr></tbody></table><blockquote><ul><li>本速查表按开发流程排列，建议从「大模型服务」→「框架编排」→「向量数据库」→「Embedding」→「文档处理」→「部署工具」的顺序了解工具链全貌。</li><li>快速上手代码均为最小可运行示例，实际使用时需替换API Key、模型名等配置。</li><li>生产环境建议关注各工具的官方文档更新，获取最新版本特性和最佳实践。</li></ul></blockquote>',90)])])}const b=r(a,[["render",n]]);export{c as __pageData,b as default};
